#include<bits/stdc++.h>
using namespace std;
int n,ans=0,f=0;
struct c{
  int l,r;
}d[1000010];
bool cmp(c a, c b) {
  return a.r<b.r; 
}
int main() {
  cin >> n;
  for (int i=1;i<=n;i++){
    cin>>d[i].l>>d[i].r;
  }
  sort(d+1,d+n+1,cmp);
  for (int i=1;i<=n;i++){
    if (f<=d[i].l) { 
      ans++;
      f=d[i].r;
    }
  }
  cout<<ans<<endl;
  return 0;
}
